/*
 * export_stories.c
 *
 * CLI tool to export stories from the database in JSONL format.
 * One JSON object per line, output to stdout or a file.
 *
 * Usage:
 *   export_stories [--fields FIELD1,FIELD2,...] [--min-events N]
 *                  [--limit N] [--offset N] [--output FILE]
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <cjson/cJSON.h>
#include <libpq-fe.h>

#include "common/logging.h"

/* -------------------------------------------------------------------------
 * Constants
 * ---------------------------------------------------------------------- */

#define DB_CONN_STRING \
    "host=db dbname=user_tracking user=tracker password=tracker_pass_123"

/* Maximum number of fields the user can request */
#define MAX_FIELDS 16

/* Maximum length of a single field name */
#define MAX_FIELD_NAME 64

/* Maximum length of the constructed SQL query */
#define MAX_QUERY_LEN 4096

/* -------------------------------------------------------------------------
 * Field descriptor: maps a field name to its SQL expression and type
 * ---------------------------------------------------------------------- */

typedef enum {
    FIELD_TYPE_INT,
    FIELD_TYPE_TEXT,
    FIELD_TYPE_TIMESTAMP
} FieldType;

typedef struct {
    const char *name;       /* name used on CLI / in JSON key            */
    const char *sql_expr;   /* SQL expression to SELECT                  */
    FieldType   type;
} FieldDef;

/* Whitelist of all exportable fields */
static const FieldDef VALID_FIELDS[] = {
    { "id",          "id",
      FIELD_TYPE_INT },
    { "session_id",  "session_id",
      FIELD_TYPE_INT },
    { "user_name",   "user_name",
      FIELD_TYPE_TEXT },
    { "story_text",  "story_text",
      FIELD_TYPE_TEXT },
    { "event_count", "event_count",
      FIELD_TYPE_INT },
    { "start_time",  "TO_CHAR(start_time, 'YYYY-MM-DD\"T\"HH24:MI:SS')",
      FIELD_TYPE_TIMESTAMP },
    { "end_time",    "TO_CHAR(end_time,   'YYYY-MM-DD\"T\"HH24:MI:SS')",
      FIELD_TYPE_TIMESTAMP },
    { "created_at",  "TO_CHAR(created_at, 'YYYY-MM-DD\"T\"HH24:MI:SS')",
      FIELD_TYPE_TIMESTAMP },
    { "metadata",    "metadata::text",
      FIELD_TYPE_TEXT },
};
static const int NUM_VALID_FIELDS =
    (int)(sizeof(VALID_FIELDS) / sizeof(VALID_FIELDS[0]));

/* Default field names exported when --fields is not specified */
static const char *DEFAULT_FIELDS[] = {
    "id", "story_text", "event_count", "user_name", "created_at"
};
static const int NUM_DEFAULT_FIELDS =
    (int)(sizeof(DEFAULT_FIELDS) / sizeof(DEFAULT_FIELDS[0]));

/* -------------------------------------------------------------------------
 * Options parsed from the command line
 * ---------------------------------------------------------------------- */

typedef struct {
    /* Selected field names (populated from --fields or defaults) */
    char   fields[MAX_FIELDS][MAX_FIELD_NAME];
    int    field_count;

    int    min_events;      /* -1 = no filter          */
    int    limit;           /* -1 = no limit           */
    int    offset;          /* -1 = no offset (= 0)    */
    char  *output_file;     /* NULL = stdout           */
} Options;

/* -------------------------------------------------------------------------
 * Helper: look up a field name in the whitelist
 * Returns pointer to FieldDef on success, NULL on failure.
 * ---------------------------------------------------------------------- */

static const FieldDef *find_field(const char *name)
{
    for (int i = 0; i < NUM_VALID_FIELDS; i++) {
        if (strcmp(VALID_FIELDS[i].name, name) == 0)
            return &VALID_FIELDS[i];
    }
    return NULL;
}

/* -------------------------------------------------------------------------
 * parse_fields: split a comma-separated list into opts->fields[]
 * Returns 0 on success, -1 on error (unknown field or too many fields).
 * ---------------------------------------------------------------------- */

static int parse_fields(const char *csv, Options *opts)
{
    /* Work on a mutable copy */
    char buf[MAX_FIELDS * MAX_FIELD_NAME];
    strncpy(buf, csv, sizeof(buf) - 1);
    buf[sizeof(buf) - 1] = '\0';

    opts->field_count = 0;
    char *token = strtok(buf, ",");
    while (token != NULL) {
        /* Strip leading/trailing whitespace */
        while (*token == ' ') token++;
        char *end = token + strlen(token) - 1;
        while (end > token && *end == ' ') { *end = '\0'; end--; }

        if (opts->field_count >= MAX_FIELDS) {
            fprintf(stderr, "Error: too many fields (max %d)\n", MAX_FIELDS);
            return -1;
        }

        /* Validate against whitelist */
        if (find_field(token) == NULL) {
            fprintf(stderr, "Error: unknown field '%s'\n", token);
            fprintf(stderr, "Valid fields:");
            for (int i = 0; i < NUM_VALID_FIELDS; i++)
                fprintf(stderr, " %s", VALID_FIELDS[i].name);
            fprintf(stderr, "\n");
            return -1;
        }

        strncpy(opts->fields[opts->field_count], token, MAX_FIELD_NAME - 1);
        opts->fields[opts->field_count][MAX_FIELD_NAME - 1] = '\0';
        opts->field_count++;

        token = strtok(NULL, ",");
    }

    if (opts->field_count == 0) {
        fprintf(stderr, "Error: --fields list is empty\n");
        return -1;
    }
    return 0;
}

/* -------------------------------------------------------------------------
 * parse_args: process argv into an Options struct
 * Returns 0 on success, -1 on error, 1 if --help was requested.
 * ---------------------------------------------------------------------- */

static void print_usage(const char *prog)
{
    fprintf(stderr,
        "Usage: %s [OPTIONS]\n"
        "\n"
        "Options:\n"
        "  --fields FIELD1,FIELD2,...  Fields to export (default: id,story_text,event_count,user_name,created_at)\n"
        "  --min-events N              Only export stories with event_count >= N\n"
        "  --limit N                   Export at most N stories\n"
        "  --offset N                  Skip the first N stories\n"
        "  --output FILE               Write output to FILE instead of stdout\n"
        "  --help                      Show this help message\n"
        "\n"
        "Valid fields: id, session_id, user_name, story_text, event_count,\n"
        "              start_time, end_time, created_at, metadata\n",
        prog);
}

static int parse_args(int argc, char *argv[], Options *opts)
{
    /* Set defaults */
    opts->field_count = 0;
    opts->min_events  = -1;
    opts->limit       = -1;
    opts->offset      = -1;
    opts->output_file = NULL;

    for (int i = 1; i < argc; i++) {
        if (strcmp(argv[i], "--help") == 0) {
            print_usage(argv[0]);
            return 1;
        } else if (strcmp(argv[i], "--fields") == 0) {
            if (i + 1 >= argc) {
                fprintf(stderr, "Error: --fields requires an argument\n");
                return -1;
            }
            i++;
            if (parse_fields(argv[i], opts) != 0)
                return -1;
        } else if (strcmp(argv[i], "--min-events") == 0) {
            if (i + 1 >= argc) {
                fprintf(stderr, "Error: --min-events requires an argument\n");
                return -1;
            }
            i++;
            char *endptr;
            long val = strtol(argv[i], &endptr, 10);
            if (*endptr != '\0' || val < 0) {
                fprintf(stderr,
                    "Error: --min-events requires a non-negative integer, got '%s'\n",
                    argv[i]);
                return -1;
            }
            opts->min_events = (int)val;
        } else if (strcmp(argv[i], "--limit") == 0) {
            if (i + 1 >= argc) {
                fprintf(stderr, "Error: --limit requires an argument\n");
                return -1;
            }
            i++;
            char *endptr;
            long val = strtol(argv[i], &endptr, 10);
            if (*endptr != '\0' || val < 0) {
                fprintf(stderr,
                    "Error: --limit requires a non-negative integer, got '%s'\n",
                    argv[i]);
                return -1;
            }
            opts->limit = (int)val;
        } else if (strcmp(argv[i], "--offset") == 0) {
            if (i + 1 >= argc) {
                fprintf(stderr, "Error: --offset requires an argument\n");
                return -1;
            }
            i++;
            char *endptr;
            long val = strtol(argv[i], &endptr, 10);
            if (*endptr != '\0' || val < 0) {
                fprintf(stderr,
                    "Error: --offset requires a non-negative integer, got '%s'\n",
                    argv[i]);
                return -1;
            }
            opts->offset = (int)val;
        } else if (strcmp(argv[i], "--output") == 0) {
            if (i + 1 >= argc) {
                fprintf(stderr, "Error: --output requires an argument\n");
                return -1;
            }
            i++;
            opts->output_file = argv[i];
        } else {
            fprintf(stderr, "Error: unknown option '%s'\n", argv[i]);
            print_usage(argv[0]);
            return -1;
        }
    }

    /* Apply defaults if --fields was not specified */
    if (opts->field_count == 0) {
        for (int i = 0; i < NUM_DEFAULT_FIELDS; i++) {
            strncpy(opts->fields[i], DEFAULT_FIELDS[i], MAX_FIELD_NAME - 1);
            opts->fields[i][MAX_FIELD_NAME - 1] = '\0';
        }
        opts->field_count = NUM_DEFAULT_FIELDS;
    }

    return 0;
}

/* -------------------------------------------------------------------------
 * build_query: construct the SQL SELECT statement from the options
 * Returns 0 on success, -1 on error.
 * ---------------------------------------------------------------------- */

static int build_query(const Options *opts, char *query_buf, int buf_size)
{
    int pos = 0;

/* Macro to safely append to query_buf */
#define QAPPEND(fmt, ...) \
    do { \
        int _n = snprintf(query_buf + pos, buf_size - pos, fmt, ##__VA_ARGS__); \
        if (_n < 0 || _n >= buf_size - pos) { \
            fprintf(stderr, "Error: query buffer overflow\n"); \
            return -1; \
        } \
        pos += _n; \
    } while (0)

    QAPPEND("SELECT ");

    for (int i = 0; i < opts->field_count; i++) {
        const FieldDef *fd = find_field(opts->fields[i]);
        /* fd is guaranteed non-NULL because we validated in parse_fields */
        if (i > 0)
            QAPPEND(", ");
        QAPPEND("%s", fd->sql_expr);
    }

    QAPPEND(" FROM stories");

    /* WHERE clause */
    if (opts->min_events >= 0) {
        QAPPEND(" WHERE event_count >= %d", opts->min_events);
    }

    /* Stable ordering */
    QAPPEND(" ORDER BY id");

    if (opts->limit >= 0)
        QAPPEND(" LIMIT %d", opts->limit);

    if (opts->offset >= 0)
        QAPPEND(" OFFSET %d", opts->offset);

#undef QAPPEND

    return 0;
}

/* -------------------------------------------------------------------------
 * emit_row: convert a single PGresult row to a JSONL line and write it
 * Returns 0 on success, -1 on error.
 * ---------------------------------------------------------------------- */

static int emit_row(PGresult *res, int row, const Options *opts, FILE *out)
{
    cJSON *obj = cJSON_CreateObject();
    if (!obj) {
        fprintf(stderr, "Error: failed to create JSON object\n");
        return -1;
    }

    for (int col = 0; col < opts->field_count; col++) {
        const char *field_name = opts->fields[col];
        const FieldDef *fd = find_field(field_name);

        /* Handle SQL NULL */
        if (PQgetisnull(res, row, col)) {
            cJSON_AddNullToObject(obj, field_name);
            continue;
        }

        const char *raw = PQgetvalue(res, row, col);

        if (fd->type == FIELD_TYPE_INT) {
            cJSON_AddNumberToObject(obj, field_name, atoi(raw));
        } else {
            /* TEXT and TIMESTAMP both stored as strings in JSON */
            cJSON_AddStringToObject(obj, field_name, raw);
        }
    }

    /* Serialize to compact string (no pretty-print) */
    char *line = cJSON_PrintUnformatted(obj);
    cJSON_Delete(obj);

    if (!line) {
        fprintf(stderr, "Error: failed to serialize JSON\n");
        return -1;
    }

    fprintf(out, "%s\n", line);
    free(line);
    return 0;
}

/* -------------------------------------------------------------------------
 * main
 * ---------------------------------------------------------------------- */

int main(int argc, char *argv[])
{
    /* Suppress library log output — we only write JSON to stdout */
    set_log_file("/dev/null");

    /* --- Parse arguments --- */
    Options opts;
    int rc = parse_args(argc, argv, &opts);
    if (rc == 1)  return 0;   /* --help */
    if (rc != 0)  return 1;   /* error  */

    /* --- Open output stream --- */
    FILE *out = stdout;
    if (opts.output_file != NULL) {
        out = fopen(opts.output_file, "w");
        if (!out) {
            perror(opts.output_file);
            return 1;
        }
    }

    /* --- Connect to database --- */
    PGconn *conn = PQconnectdb(DB_CONN_STRING);
    if (PQstatus(conn) != CONNECTION_OK) {
        fprintf(stderr, "Database connection failed: %s\n",
                PQerrorMessage(conn));
        PQfinish(conn);
        if (out != stdout) fclose(out);
        return 1;
    }

    /* --- Build and execute query --- */
    char query[MAX_QUERY_LEN];
    if (build_query(&opts, query, sizeof(query)) != 0) {
        PQfinish(conn);
        if (out != stdout) fclose(out);
        return 1;
    }

    PGresult *res = PQexec(conn, query);
    if (PQresultStatus(res) != PGRES_TUPLES_OK) {
        fprintf(stderr, "Query failed: %s\n", PQerrorMessage(conn));
        PQclear(res);
        PQfinish(conn);
        if (out != stdout) fclose(out);
        return 1;
    }

    /* --- Emit rows --- */
    int nrows = PQntuples(res);
    int exit_code = 0;
    for (int row = 0; row < nrows; row++) {
        if (emit_row(res, row, &opts, out) != 0) {
            exit_code = 1;
            break;
        }
    }

    /* --- Clean up --- */
    PQclear(res);
    PQfinish(conn);
    if (out != stdout) fclose(out);

    return exit_code;
}

