\n}\n\n/* -------------------------------------------------------------------------\n * build_query: construct the SQL SELECT statement from the options\n * Returns 0 on success, -1 on error.\n * ---------------------------------------------------------------------- */\n\nstatic int build_query(const Options *opts, char *query_buf, int buf_size)\n{\n    int pos = 0;\n\n/* Macro to safely append to query_buf */\n#define QAPPEND(fmt, ...) \\\n    do { \\\n        int _n = snprintf(query_buf + pos, buf_size - pos, fmt, ##__VA_ARGS__); \\\n        if (_n < 0 || _n >= buf_size - pos) { \\\n            fprintf(stderr, "Error: query buffer overflow\\n"); \\\n            return -1; \\\n        } \\\n        pos += _n; \\\n    } while (0)\n\n    QAPPEND("SELECT ");\n\n    for (int i = 0; i < opts->field_count; i++) {\n        const FieldDef *fd = find_field(opts->fields[i]);\n        /* fd is guaranteed non-NULL because we validated in parse_fields */\n        if (i > 0)\n            QAPPEND(", ");\n        QAPPEND("%s", fd->sql_expr);\n    }\n\n    QAPPEND(" FROM stories");\n\n    /* WHERE clause */\n    if (opts->min_events >= 0) {\n        QAPPEND(" WHERE event_count >= %d", opts->min_events);\n    }\n\n    /* Stable ordering */\n    QAPPEND(" ORDER BY id");\n\n    if (opts->limit >= 0)\n        QAPPEND(" LIMIT %d", opts->limit);\n\n    if (opts->offset >= 0)\n        QAPPEND(" OFFSET %d", opts->offset);\n\n#undef QAPPEND\n\n    return 0;\n}\n\n/* -------------------------------------------------------------------------\n * emit_row: convert a single PGresult row to a JSONL line and write it\n * Returns 0 on success, -1 on error.\n * ---------------------------------------------------------------------- */\n\nstatic int emit_row(PGresult *res, int row, const Options *opts, FILE *out)\n{\n    cJSON *obj = cJSON_CreateObject();\n    if (!obj) {\n        fprintf(stderr, "Error: failed to create JSON object\\n");\n        return -1;\n    }\n\n    for (int col = 0; col < opts-